1. using System;
2. using Microsoft.EntityFrameworkCore;
3. using System.Linq;
4. using System.Net;
5. using ContosoUniversity.Data;
6. using ContosoUniversity.Models;
7. using System.Diagnostics;
8. using Microsoft.AspNetCore.Mvc;
9. using Microsoft.AspNetCore.Mvc.ModelBinding;
10. using ContosoUniversity;
11. using Microsoft.Extensions.Configuration; // for PaginatedList
12. 
13. namespace ContosoUniversity.Controllers
14. {
15.     public class StudentsController : BaseController
16.     {
17.         public StudentsController(SchoolContext context) : base(context)
18.         {
19.         }
20. 
21.         // GET: Students - Admins and Teachers can view
22.         public ActionResult Index(string sortOrder, string currentFilter, string searchString, int? page)
23.         {
24.             ViewBag.CurrentSort = sortOrder;
25.             ViewBag.NameSortParm = String.IsNullOrEmpty(sortOrder) ? "name_desc" : "";
26.             ViewBag.DateSortParm = sortOrder == "Date" ? "date_desc" : "Date";
27. 
28.             if (searchString != null)
29.             {
30.                 page = 1;
31.             }
32.             else
33.             {
34.                 searchString = currentFilter;
35.             }
36. 
37.             ViewBag.CurrentFilter = searchString;
38. 
39.             var students = from s in db.Students
40.                            select s;
41. 
42.             if (!String.IsNullOrEmpty(searchString))
43.             {
44.                 students = students.Where(s => s.LastName.Contains(searchString)
45.                                        || s.FirstMidName.Contains(searchString));
46.             }
47. 
48.             switch (sortOrder)
49.             {
50.                 case "name_desc":
51.                     students = students.OrderByDescending(s => s.LastName);
52.                     break;
53.                 case "Date":
54.                     students = students.OrderBy(s => s.EnrollmentDate);
55.                     break;
56.                 case "date_desc":
57.                     students = students.OrderByDescending(s => s.EnrollmentDate);
58.                     break;
59.                 default:
60.                     students = students.OrderBy(s => s.LastName);
61.                     break;
62.             }
63. 
64.             int pageSize = 10;
65.             int pageNumber = (page ?? 1);
66.             return View(PaginatedList<Student>.Create(students, pageNumber, pageSize));
67.         }
68. 
69.         // GET: Students/Details/5 - Admins and Teachers can view details
70.         public ActionResult Details(int? id)
71.         {
72.             if (id == null)
73.             {
74.                 return new StatusCodeResult((int)HttpStatusCode.BadRequest);
75.             }
76.             Student student = db.Students
77.                 .Include(s => s.Enrollments)
78.                     .ThenInclude(e => e.Course)
79.                 .Where(s => s.ID == id).Single();
80.             if (student == null)
81.             {
82.                 return NotFound();
83.             }
84.             return View(student);
85.         }
86. 
87.         // GET: Students/Create
88.         public ActionResult Create()
89.         {
90.             var student = new Student
91.             {
92.                 EnrollmentDate = DateTime.Today // Set default to today's date
93.             };
94.             return View(student);
95.         }
96. 
97.         // POST: Students/Create
98.         [HttpPost]
99.         [ValidateAntiForgeryToken]
100.         public ActionResult Create([Bind("LastName", "FirstMidName", "EnrollmentDate")] Student student)
101.         {
102.             try
103.             {
104.                 // Validate EnrollmentDate is not default/minimum value
105.                 if (student.EnrollmentDate == DateTime.MinValue || student.EnrollmentDate == default(DateTime))
106.                 {
107.                     ModelState.AddModelError("EnrollmentDate", "Please enter a valid enrollment date.");
108.                 }
109. 
110.                 // Ensure EnrollmentDate is within valid SQL Server datetime range
111.                 if (student.EnrollmentDate < new DateTime(1753, 1, 1) || student.EnrollmentDate > new DateTime(9999, 12, 31))
112.                 {
113.                     ModelState.AddModelError("EnrollmentDate", "Enrollment date must be between 1753 and 9999.");
114.                 }
115. 
116.                 if (ModelState.IsValid)
117.                 {
118.                     db.Students.Add(student);
119.                     db.SaveChanges();
120. 
121.                     // Send notification for student creation
122.                     var studentName = $"{student.FirstMidName} {student.LastName}";
123.                     SendEntityNotification("Student", student.ID.ToString(), studentName, EntityOperation.CREATE);
124. 
125.                     return RedirectToAction("Index");
126.                 }
127.             }
128.             catch (Exception ex)
129.             {
130.                 Trace.TraceError($"Error creating student: {ex.Message} | Student: {student?.FirstMidName} {student?.LastName} | EnrollmentDate: {student?.EnrollmentDate} | Stack: {ex.StackTrace}");
131.                 ModelState.AddModelError("", "Unable to save changes. Try again, and if the problem persists see your system administrator.");
132.             }
133.             return View(student);
134.         }
135. 
136.         // GET: Students/Edit/5
137.         public ActionResult Edit(int? id)
138.         {
139.             if (id == null)
140.             {
141.                 return new StatusCodeResult((int)HttpStatusCode.BadRequest);
142.             }
143.             Student student = db.Students.Find(id);
144.             if (student == null)
145.             {
146.                 return NotFound();
147.             }
148.             return View(student);
149.         }
150. 
151.         // POST: Students/Edit/5
152.         [HttpPost]
153.         [ValidateAntiForgeryToken]
154.         public ActionResult Edit([Bind("ID", "LastName", "FirstMidName", "EnrollmentDate")] Student student)
155.         {
156.             try
157.             {
158.                 // Validate EnrollmentDate is not default/minimum value
159.                 if (student.EnrollmentDate == DateTime.MinValue || student.EnrollmentDate == default(DateTime))
160.                 {
161.                     ModelState.AddModelError("EnrollmentDate", "Please enter a valid enrollment date.");
162.                 }
163. 
164.                 // Ensure EnrollmentDate is within valid SQL Server datetime range
165.                 if (student.EnrollmentDate < new DateTime(1753, 1, 1) || student.EnrollmentDate > new DateTime(9999, 12, 31))
166.                 {
167.                     ModelState.AddModelError("EnrollmentDate", "Enrollment date must be between 1753 and 9999.");
168.                 }
169. 
170.                 if (ModelState.IsValid)
171.                 {
172.                     db.Entry(student).State = EntityState.Modified;
173.                     db.SaveChanges();
174. 
175.                     // Send notification for student update
176.                     var studentName = $"{student.FirstMidName} {student.LastName}";
177.                     SendEntityNotification("Student", student.ID.ToString(), studentName, EntityOperation.UPDATE);
178. 
179.                     return RedirectToAction("Index");
180.                 }
181.             }
182.             catch (Exception ex)
183.             {
184.                 Trace.TraceError($"Error editing student: {ex.Message} | Student ID: {student?.ID} | Student: {student?.FirstMidName} {student?.LastName} | EnrollmentDate: {student?.EnrollmentDate} | Stack: {ex.StackTrace}");
185.                 ModelState.AddModelError("", "Unable to save changes. Try again, and if the problem persists see your system administrator.");
186.             }
187.             return View(student);
188.         }
189. 
190.         // GET: Students/Delete/5
191.         public ActionResult Delete(int? id)
192.         {
193.             if (id == null)
194.             {
195.                 return new StatusCodeResult((int)HttpStatusCode.BadRequest);
196.             }
197.             Student student = db.Students.Find(id);
198.             if (student == null)
199.             {
200.                 return NotFound();
201.             }
202.             return View(student);
203.         }
204. 
205.         // POST: Students/Delete/5
206.         [HttpPost, ActionName("Delete")]
207.         [ValidateAntiForgeryToken]
208.         public ActionResult DeleteConfirmed(int id)
209.         {
210.             try
211.             {
212.                 Student student = db.Students.Find(id);
213.                 var studentName = $"{student.FirstMidName} {student.LastName}";
214.                 db.Students.Remove(student);
215.                 db.SaveChanges();
216. 
217.                 // Send notification for student deletion
218.                 SendEntityNotification("Student", id.ToString(), studentName, EntityOperation.DELETE);
219. 
220.                 return RedirectToAction("Index");
221.             }
222.             catch (Exception ex)
223.             {
224.                 Trace.TraceError($"Error deleting student: {ex.Message} | Student ID: {id} | Stack: {ex.StackTrace}");
225.                 TempData["ErrorMessage"] = "Unable to delete the student. Try again, and if the problem persists see your system administrator.";
226.                 return RedirectToAction("Index");
227.             }
228.         }
229. 
230.         protected override void Dispose(bool disposing)
231.         {
232.             if (disposing)
233.             {
234.                 // Base class will dispose db and notificationService
235.             }
236.             base.Dispose(disposing);
237.         }
238.     }
239. }
