using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PaginatedListTests
    {
        private IQueryable<int> CreateSource(int count)
        {
            return Enumerable.Range(1, count).AsQueryable();
        }

        [Fact]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            var source = CreateSource(25);
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(1, result[0]);
            Assert.Equal(10, result[9]);
        }

        [Fact]
        public void Create_MiddlePage_ReturnsCorrectItems()
        {
            var source = CreateSource(25);
            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(2, result.PageIndex);
            Assert.Equal(11, result[0]);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = CreateSource(25);
            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(3, result.PageIndex);
            Assert.Equal(21, result[0]);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var result = PaginatedList<int>.Create(CreateSource(20), 1, 10);
            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var result = PaginatedList<int>.Create(CreateSource(20), 2, 10);
            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var result = PaginatedList<int>.Create(CreateSource(20), 2, 10);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var result = PaginatedList<int>.Create(CreateSource(20), 1, 10);
            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_SinglePage_NoPreviousOrNext()
        {
            var result = PaginatedList<int>.Create(CreateSource(5), 1, 10);

            Assert.Equal(1, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
            Assert.Equal(1, result.PageIndex);
        }

        [Fact]
        public void Create_ExactPageSize_CalculatesCorrectTotalPages()
        {
            var result = PaginatedList<int>.Create(CreateSource(10), 1, 10);
            Assert.Equal(1, result.TotalPages);
            Assert.Equal(10, result.Count);
        }

        [Fact]
        public void TotalPages_CalculatedWithCeiling()
        {
            // 11 items / 10 per page = 2 pages (ceiling)
            var result = PaginatedList<int>.Create(CreateSource(11), 1, 10);
            Assert.Equal(2, result.TotalPages);
        }
    }
}

using System;
using System.Linq;
using System.Threading;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests
    {
        private void DrainQueue(NotificationService service)
        {
            while (service.ReceiveNotification() != null) { }
        }

        [Fact]
        public void SendAndReceive_BasicNotification_Works()
        {
            using var service = new NotificationService();
            DrainQueue(service);

            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("Student 'John Doe'", notification.Message);
            Assert.Contains("created", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_MessageContainsName()
        {
            using var service = new NotificationService();
            DrainQueue(service);

            service.SendNotification("Course", "42", "Chemistry 101", EntityOperation.UPDATE, "Teacher");

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Course 'Chemistry 101'", notification.Message);
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_MessageContainsId()
        {
            using var service = new NotificationService();
            DrainQueue(service);

            service.SendNotification("Department", "7", EntityOperation.DELETE, "System");

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Department (ID: 7)", notification.Message);
            Assert.Contains("deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_NullDisplayName_UsesIdFallback()
        {
            using var service = new NotificationService();
            DrainQueue(service);

            service.SendNotification("Student", "5", null, EntityOperation.CREATE);

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Student (ID: 5)", notification.Message);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            using var service = new NotificationService();
            DrainQueue(service);

            service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            using var service = new NotificationService();
            DrainQueue(service);

            var result = service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void SendNotification_MultipleMessages_DequeuedInOrder()
        {
            using var service = new NotificationService();
            DrainQueue(service);

            service.SendNotification("A", "1", "First", EntityOperation.CREATE);
            service.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
            service.SendNotification("C", "3", "Third", EntityOperation.DELETE);

            var first = service.ReceiveNotification();
            var second = service.ReceiveNotification();
            var third = service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
            Assert.Equal("C", third.EntityType);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "created")]
        [InlineData(EntityOperation.UPDATE, "updated")]
        [InlineData(EntityOperation.DELETE, "deleted")]
        public void GenerateMessage_AllOperations_CorrectVerb(EntityOperation operation, string expectedVerb)
        {
            using var service = new NotificationService();
            DrainQueue(service);

            service.SendNotification("Entity", "1", "Test", operation);

            var notification = service.ReceiveNotification();
            Assert.Contains(expectedVerb, notification.Message);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            using var service = new NotificationService();
            // MarkAsRead is a no-op, just verify it doesn't throw
            service.MarkAsRead(1);
            service.MarkAsRead(999);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            service.Dispose();
            // Should not throw on double dispose
            service.Dispose();
        }

        [Fact]
        public void SendNotification_CreatedAtIsSet()
        {
            using var service = new NotificationService();
            DrainQueue(service);

            var before = DateTime.Now;
            service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_TwoArgOverload_DelegatesToFiveArg()
        {
            using var service = new NotificationService();
            DrainQueue(service);

            service.SendNotification("Instructor", "10", EntityOperation.UPDATE);

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Instructor", notification.EntityType);
            Assert.Equal("10", notification.EntityId);
            Assert.Contains("Instructor (ID: 10)", notification.Message);
        }
    }
}

using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;
            _context = new SchoolContext(options);
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        private Student SeedStudent(string lastName = "Smith", string firstName = "John", DateTime? enrollmentDate = null)
        {
            var student = new Student
            {
                LastName = lastName,
                FirstMidName = firstName,
                EnrollmentDate = enrollmentDate ?? new DateTime(2023, 9, 1)
            };
            _context.Students.Add(student);
            _context.SaveChanges();
            return student;
        }

        // Index tests
        [Fact]
        public void Index_NoParams_ReturnsViewWithStudentsOrderedByLastName()
        {
            SeedStudent("Zebra", "Alice");
            SeedStudent("Alpha", "Bob");

            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Alpha", model[0].LastName);
            Assert.Equal("Zebra", model[1].LastName);
        }

        [Fact]
        public void Index_NameDescSort_ReturnsDescendingOrder()
        {
            SeedStudent("Alpha", "A");
            SeedStudent("Zebra", "Z");

            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Equal("Zebra", model[0].LastName);
            Assert.Equal("Alpha", model[1].LastName);
        }

        [Fact]
        public void Index_DateSort_ReturnsOrderedByDate()
        {
            SeedStudent("B", "B", new DateTime(2023, 1, 1));
            SeedStudent("A", "A", new DateTime(2020, 1, 1));

            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Equal("A", model[0].LastName); // Earlier date first
        }

        [Fact]
        public void Index_DateDescSort_ReturnsReverseOrderByDate()
        {
            SeedStudent("B", "B", new DateTime(2020, 1, 1));
            SeedStudent("A", "A", new DateTime(2023, 1, 1));

            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Equal("A", model[0].LastName); // Later date first
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            SeedStudent("Smith", "John");
            SeedStudent("Jones", "Jane");

            var result = _controller.Index(null, null, "Smith", null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
            Assert.Equal("Smith", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            SeedStudent("Smith", "John");
            SeedStudent("Jones", "Jane");

            var result = _controller.Index(null, null, "Jane", null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
            Assert.Equal("Jones", model[0].LastName);
        }

        [Fact]
        public void Index_SearchStringNull_UsesCurrentFilter()
        {
            SeedStudent("Smith", "John");
            SeedStudent("Jones", "Jane");

            var result = _controller.Index(null, "Smith", null, null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
        }

        [Fact]
        public void Index_Pagination_RespectsPageSize()
        {
            for (int i = 0; i < 15; i++)
                SeedStudent($"Student{i:D2}", "First");

            var result = _controller.Index(null, null, null, 1) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Equal(10, model.Count);
            Assert.True(model.HasNextPage);
            Assert.False(model.HasPreviousPage);
        }

        [Fact]
        public void Index_SetsViewBagSortParms()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_NameDescSort_SetsNameSortParmToEmpty()
        {
            _controller.Index("name_desc", null, null, null);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_DateSort_SetsDateSortParmToDateDesc()
        {
            _controller.Index("Date", null, null, null);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        // Details tests
        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var student = SeedStudent();
            // Add enrollment with course for Include
            var dept = new Department { Name = "Test", Budget = 100, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            var course = new Course { CourseID = 1001, Title = "Test Course", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();
            _context.Enrollments.Add(new Enrollment { StudentID = student.ID, CourseID = 1001, Grade = Grade.A });
            _context.SaveChanges();

            var result = _controller.Details(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        // Create GET tests
        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        // Create POST tests
        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
