namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;
            _context = new SchoolContext(options);
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        private Instructor SeedInstructor(string lastName = "Doe", string firstName = "John")
        {
            var instructor = new Instructor
            {
                LastName = lastName,
                FirstMidName = firstName,
                HireDate = new DateTime(2010, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();
            return instructor;
        }

        private (Instructor instructor, Course course, Department dept) SeedInstructorWithCourse()
        {
            var instructor = SeedInstructor();
            var dept = new Department
            {
                Name = "TestDept",
                Budget = 100000,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = dept.DepartmentID,
                Enrollments = new List<Enrollment>()
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var ca = new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            };
