using System;
using System.Collections.Generic;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;
            _context = new SchoolContext(options);
            _controller = new NotificationsController(_context);
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        private void DrainQueue()
        {
            using var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            DrainQueue();

            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            DrainQueue();
            // Enqueue some notifications via the service
            using var service = new NotificationService();
            service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
            service.SendNotification("Course", "2", "Test2", EntityOperation.UPDATE);

            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void MarkAsRead_ReturnsJsonSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            DrainQueue();
            using var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Entity", i.ToString(), $"Name{i}", EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();
            Assert.IsType<JsonResult>(result);
            // The controller limits to 10, remaining 5 should still be in queue
        }
    }
}

using System;
