using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class DbInitializerTests
    {
        private SchoolContext CreateContext(string dbName)
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsAllData()
        {
            using var context = CreateContext(nameof(Initialize_EmptyDatabase_SeedsAllData));

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
            Assert.Equal(5, context.Instructors.Count());
            Assert.Equal(4, context.Departments.Count());
            Assert.Equal(7, context.Courses.Count());
            Assert.Equal(3, context.OfficeAssignments.Count());
            Assert.Equal(8, context.CourseAssignments.Count());
            Assert.True(context.Enrollments.Count() >= 11);
        }

        [Fact]
        public void Initialize_AlreadySeeded_DoesNotDuplicateData()
        {
            using var context = CreateContext(nameof(Initialize_AlreadySeeded_DoesNotDuplicateData));

            DbInitializer.Initialize(context);
            var studentCount = context.Students.Count();
            var courseCount = context.Courses.Count();

            // Call again
            DbInitializer.Initialize(context);

            Assert.Equal(studentCount, context.Students.Count());
            Assert.Equal(courseCount, context.Courses.Count());
        }

        [Fact]
        public void Initialize_SeedsStudentsWithCorrectData()
        {
            using var context = CreateContext(nameof(Initialize_SeedsStudentsWithCorrectData));
            DbInitializer.Initialize(context);

            var carson = context.Students.Single(s => s.LastName == "Alexander");
            Assert.Equal("Carson", carson.FirstMidName);
            Assert.Equal(DateTime.Parse("2010-09-01"), carson.EnrollmentDate);
        }

        [Fact]
        public void Initialize_SeedsDepartmentsWithAdministrators()
        {
            using var context = CreateContext(nameof(Initialize_SeedsDepartmentsWithAdministrators));
            DbInitializer.Initialize(context);

            var english = context.Departments.Include(d => d.Administrator)
                .Single(d => d.Name == "English");
            Assert.NotNull(english.InstructorID);
            Assert.Equal(350000, english.Budget);
        }

        [Fact]
        public void Initialize_SeedsEnrollmentsWithGrades()
        {
            using var context = CreateContext(nameof(Initialize_SeedsEnrollmentsWithGrades));
            DbInitializer.Initialize(context);

            var alexander = context.Students.Single(s => s.LastName == "Alexander");
            var chemistryEnrollment = context.Enrollments
                .Single(e => e.StudentID == alexander.ID && e.Course.Title == "Chemistry");
            Assert.Equal(Grade.A, chemistryEnrollment.Grade);
        }
    }
}

