+using System;
+using System.Linq;
+using System.Threading;
+using ContosoUniversity.Models;
+using ContosoUniversity.Services;
+using Xunit;
+
+namespace ContosoUniversity.Tests.Services
+{
+    public class NotificationServiceTests
+    {
+        private void DrainQueue(NotificationService service)
+        {
+            while (service.ReceiveNotification() != null) { }
+        }
+
+        [Fact]
+        public void SendAndReceive_BasicNotification_Works()
+        {
+            using var service = new NotificationService();
+            DrainQueue(service);
+
+            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");
+
+            var notification = service.ReceiveNotification();
+            Assert.NotNull(notification);
+            Assert.Equal("Student", notification.EntityType);
+            Assert.Equal("1", notification.EntityId);
+            Assert.Equal("CREATE", notification.Operation);
+            Assert.Contains("Student 'John Doe'", notification.Message);
+            Assert.Contains("created", notification.Message);
+            Assert.Equal("Admin", notification.CreatedBy);
+            Assert.False(notification.IsRead);
+        }
+
+        [Fact]
+        public void SendNotification_WithDisplayName_MessageContainsName()
+        {
+            using var service = new NotificationService();
+            DrainQueue(service);
+
+            service.SendNotification("Course", "42", "Chemistry 101", EntityOperation.UPDATE, "Teacher");
+
+            var notification = service.ReceiveNotification();
+            Assert.NotNull(notification);
+            Assert.Contains("Course 'Chemistry 101'", notification.Message);
+            Assert.Contains("updated", notification.Message);
+        }
+
+        [Fact]
+        public void SendNotification_WithoutDisplayName_MessageContainsId()
+        {
+            using var service = new NotificationService();
+            DrainQueue(service);
+
+            service.SendNotification("Department", "7", EntityOperation.DELETE, "System");
+
+            var notification = service.ReceiveNotification();
+            Assert.NotNull(notification);
+            Assert.Contains("Department (ID: 7)", notification.Message);
+            Assert.Contains("deleted", notification.Message);
+        }
+
+        [Fact]
+        public void SendNotification_NullDisplayName_UsesIdFallback()
+        {
+            using var service = new NotificationService();
+            DrainQueue(service);
+
+            service.SendNotification("Student", "5", null, EntityOperation.CREATE);
+
+            var notification = service.ReceiveNotification();
+            Assert.NotNull(notification);
+            Assert.Contains("Student (ID: 5)", notification.Message);
+        }
+
+        [Fact]
+        public void SendNotification_NullUserName_DefaultsToSystem()
+        {
+            using var service = new NotificationService();
+            DrainQueue(service);
+
+            service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
+
+            var notification = service.ReceiveNotification();
+            Assert.NotNull(notification);
+            Assert.Equal("System", notification.CreatedBy);
+        }
+
+        [Fact]
+        public void ReceiveNotification_EmptyQueue_ReturnsNull()
+        {
+            using var service = new NotificationService();
+            DrainQueue(service);
+
+            var result = service.ReceiveNotification();
+            Assert.Null(result);
+        }
+
+        [Fact]
+        public void SendNotification_MultipleMessages_DequeuedInOrder()
+        {
+            using var service = new NotificationService();
+            DrainQueue(service);
+
+            service.SendNotification("A", "1", "First", EntityOperation.CREATE);
+            service.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
+            service.SendNotification("C", "3", "Third", EntityOperation.DELETE);
+
+            var first = service.ReceiveNotification();
+            var second = service.ReceiveNotification();
+            var third = service.ReceiveNotification();
+
+            Assert.Equal("A", first.EntityType);
+            Assert.Equal("B", second.EntityType);
+            Assert.Equal("C", third.EntityType);
+        }
+
+        [Theory]
+        [InlineData(EntityOperation.CREATE, "created")]
+        [InlineData(EntityOperation.UPDATE, "updated")]
+        [InlineData(EntityOperation.DELETE, "deleted")]
+        public void GenerateMessage_AllOperations_CorrectVerb(EntityOperation operation, string expectedVerb)
+        {
